fn n_to_vec(n: u64, l: usize) -> Vec<u8> {
    let mut res = vec![0; l];
    let mut n = n;
    for i in (0..l).rev() {
        if n % 2 == 1 {
            res[i] = 1;
        }
        n /= 2;
    }
    res
}

fn vec_to_n(v: Vec<u8>) -> u64 {
    let mut res = 0;
    for i in 0..v.len() {
        res *= 2;
        if v[i] == 1 {
            res += 1;
        }
    }
    res
}

